SELECT sales_order.order_id, CONCAT( sales_customer.First_Name," ", sales_customer.Last_Name) AS "Customer's Name", sales_order.Order_status, sales_order.order_date, sales_order.Required_Date, sales_order.Shipped_Date, sales_store.Store_Name, CONCAT(sales_staff.First_Name, " ", sales_staff.Last_Name) AS "Staff Name" FROM sales_staff JOIN sales_order ON sales_staff.Staff_Id = sales_order.Staff_Id JOIN sales_customer ON sales_customer.Customer_Id = sales_order.Customer_Id JOIN sales_store ON sales_store.Store_Id = sales_order.Store_Id;